const q = $('Läs meddelande').first().json.message || '';
const flow = items[0].json;
const hadHttpError = Boolean(flow.error);
const raw = hadHttpError ? '' : String(flow.text ?? flow.data?.text ?? flow.output ?? '');
const cleaned = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
let parsed = null;
try {
  parsed = cleaned ? JSON.parse(cleaned) : null;
} catch {}
const lower = String(q).toLowerCase();
const fallbackCategory = /tidsmaskin|paradox/.test(lower)
  ? 'time_machine_issue'
  : /fortfarande d[oö]d|r[oö]r sig inte|[aå]teruppliv|stilla ?d[oö]d/.test(lower)
    ? 'resurrection_support'
    : /fick tv[aå]|leverans|frakt|skadad|saknas/.test(lower)
      ? 'shipping_or_subscription'
      : 'general_question';
const fallbackEscalate = /eskalera|arg|reklamera|fel fisk|fel produkt|fortfarande d[oö]d|paradox/.test(lower);
const reply = parsed?.reply || raw || 'Tyvärr kunde jag inte generera svar just nu. Kontrollera Flowise eller OpenAI-installationen.';
const escalate = typeof parsed?.escalate === 'boolean' ? parsed.escalate : hadHttpError || fallbackEscalate || reply.length < 18;
const category = parsed?.category || fallbackCategory;
const reason = parsed?.reason || (escalate ? 'Ärendet är för oklart eller för konstigt för första linjen.' : 'Kan hanteras i första linjen med standardsvar.');
items[0].json = { reply, escalate, category, reason, meta: { question: q, raw } };
return items;
